final:
module JK_latch (  
    input obf_J,  
    input K,  
    input clk,  
    output reg Q  
);  
    always @(posedge clk) begin  
        if (obf_J && K)  
            Q <= ~Q;  
        else if (obf_J)  
            Q <= 1;  
        else if (K)  
            Q <= 0;  
        // retain previous state if both obf_J and K are low  
    end  
endmodule
